#include<bits/stdc++.h>
using namespace std;
int main(){
    int n,m,a[1000005];
    cin>>n>>m;
    for(int i=1;i<=n;i++) cin>>a[i];
    for(int i=1;i<=m;i++){
        int zhong;
        cin>>zhong;
        if(zhong==1){
            int x,y;
            cin>>x>>y;
            for(int i=x;i<=n;i+=x){
                a[i]+=y;
            }
        }else{
            int j;
            cin>>j;
            cout<<a[j]<<"\n";
        }
    }
    return 0;
}
